var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"저, 저기… 이제 그만해줘!","JPN":"あ、あの……もうやめて！","ENG":"U-um... Please stop!","TWN":"那，那個……現在停手吧！"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"팔이라면 우, 우리가 어떻게든 해볼 테니까…","JPN":"腕なら、わ、私たちが何とかしてみるから……","ENG":"W-we'll try to put her arm back, so...","TWN":"如果是手臂的話，我，我們會想辦法的……"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"누, 누가 좀 도와주세요!","JPN":"だ、誰か助けてください！","ENG":"P-please somebody help me!","TWN":"誰，誰來幫幫我！"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L6_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"어떻게든 해 본다고…?","JPN":"何とかしてみる……？","ENG":"You're going to try...?","TWN":"你說要想辦法……？"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이 아이가 당할 때, 막아서는 사람 한 명도 없었잖아!","JPN":"この子がやられている時に、それを止める人は一人もいなかったじゃない！","ENG":"There was no one stopping her when the kid was attacked!","TWN":"這個孩子受罪的時候，你們沒一個人站出來阻止吧！"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"너희들은 우리를 인간 취급도 할 생각이 없는 거겠지!","JPN":"あなたたちは私たちを人間扱いするつもりなんてないんでしょう！","ENG":"You treat us as if we're not even human!","TWN":"你們根本就不把我們當人看待吧！"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"너… 사샤 맞지?","JPN":"あなた……サシャよね？","ENG":"You're... Sasha, right?","TWN":"你……是莎夏吧？"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"이 아이는 나처럼 되고 싶다고 했어.","JPN":"この子は私みたいになりたいって言ったの。","ENG":"The kid said that she wanted to be just like me.","TWN":"這個孩子說想變得像我一樣。"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"엄청 튼튼하고 빠르다고 해서 시험해 본 거였는데, 이렇게나 약할 줄은 몰랐어.","JPN":"めちゃくちゃ丈夫で速いって言うから試してみただけなのに、ここまで弱いと思わなかった。","ENG":"She claimed that she was strong and fast, and I wanted to test her. I didn't know she was this weak.","TWN":"她說自己很結實，跑得也很快，所以我才試了一下，沒想到這麼弱。"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"우린 있지? 인형이 되기 위해서 신체를 한 부위씩, 교체하는 수술을 받았다구.","JPN":"私たちはね、人形になるために身体を一カ所ずつ、交替する手術を受けたのよ。","ENG":"You know what? We received surgery to become a Doll by replacing our limbs one by one.","TWN":"我們為了變成娃娃，要一個一個替換掉身體的部位。"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"원하는대로 해줬을 뿐인데… 왜 화를 내는거야?","JPN":"望みどおりにしてやっただけなのに……どうして怒ってるのかな？","ENG":"I just did what she wanted... but why are you so mad about it?","TWN":"我只是按她的要求去做……為什麼要生氣？"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛, 화나게 했다면 미안해.","JPN":"ひひっ、怒らせたならごめんね。","ENG":"Hehe. I'm sorry if I made you angry.","TWN":"嘻嘻，如果讓你感到不高興，我很抱歉。"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"팔 정도는 인형으로 대체해도 문제없을 거라고 생각하는데…","JPN":"腕くらい人形に代わっても問題ないと思うけど……","ENG":"I thought it wouldn't be a problem if one of her arms got replaced with what we have.","TWN":"我覺得給她換上娃娃的手臂應該沒問題……"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"아참, 그러고 보니 이름도 안 물어봤었네.","JPN":"そうだ、そういえば名前も聞いてなかった。","ENG":"Oh, right. I never even asked what her name was.","TWN":"啊，對了，說起來還沒問名字呢。"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"나중에 물어봐야지. 다음엔 뭐 하고 놀면 좋을까?","JPN":"後で聞いてみようっと。次は何して遊んだらいいかな？","ENG":"I'll ask her later. Until then, what should we play next?","TWN":"以後再問吧，下次玩什麼好呢？"},"stage":{"bg":"CORRIDOR_05","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"……!!","JPN":"……！！","ENG":"...!!","TWN":"……！！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤!","JPN":"サシャ！","ENG":"Sasha!","TWN":"莎夏！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"……???","JPN":"……？？？","ENG":"...???","TWN":"……？？？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"당장 사라져. 더 이상 말하고 싶지도 않아.","JPN":"さっさと消えて。もう話したくもない。","ENG":"Get out of my sight. I don't want to talk to you.","TWN":"立刻給我消失，我不想再和你多說廢話。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"또 마을 사람을 건드렸다간 그땐 정말 가만두지 않겠어!","JPN":"また村の人たちに手を出したら、その時はただではおかないから！","ENG":"If you lay your hands on another villager, it won't end with just a slap!","TWN":"如果再敢動村裡的人，那時候我絕不會放過你！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"어라…? 나 지금 뺨 맞은 거야?","JPN":"あれ……？　私、今頬を殴られた？","ENG":"Huh...? Did you just slap me?","TWN":"嗯…？我剛剛被打了嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"히, 히익! 드드드, 드레카!","JPN":"ひ、ひいっ！　ドドド、ドレカ！","ENG":"E-eeek! D-D-D-D-Dreka!","TWN":"呃，呃！德德德，德蕾卡！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L39_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤한테 가까이 다가오지 마!","JPN":"サシャに近づかないで！","ENG":"Don't you dare get close to Sasha!","TWN":"不要靠近莎夏！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"오랜만이야… 누구한테 맞아본거.","JPN":"久しぶりだよ……誰かに殴られたの。","ENG":"It's been so long... since anyone hit me.","TWN":"好久沒被打了……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"아프지도 않은데… 뭔가 기분이 이상해.","JPN":"痛くもないのに……何か変な気分。","ENG":"It doesn't hurt, but... something feels strange.","TWN":"雖然不會痛……但感覺有點奇怪。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"언니. 나 방에 가 있을게. 이따가 꼭 와줘…?","JPN":"姉さん。私、部屋に戻ってるね。後で絶対来てね……？","ENG":"Sis, I'll be in my room. Come by my room later, okay...?","TWN":"姊姊，我先回房間了，等一下要來找我喔……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK"},{"id":"L47_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"하아… 하아…!","JPN":"はあ……はあ……！","ENG":"*Huff* *Huff*","TWN":"哈啊……哈啊……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤?","JPN":"サシャ？","ENG":"Sasha?","TWN":"莎夏？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"으으으……!","JPN":"ううう……！","ENG":"Ngh...!","TWN":"呃呃呃……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"가, 갑자기 왜 그래?!","JPN":"い、いきなりどうしたの！？","ENG":"W-what's wrong?!","TWN":"她，她突然怎麼了？！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이건…!","JPN":"これは……！","ENG":"This is...!","TWN":"這是……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"어, 엄청 뜨거워…!","JPN":"す、すごく熱い……！","ENG":"S-she's burning up...!","TWN":"好，好燙……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"집에 약이 남아있었어. 서둘러야 해!","JPN":"家に薬が残ってる。急がないと！","ENG":"There should still be some meds at home. I need to go get them in a hurry!","TWN":"家裡還有藥，動作要快！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"아냐 마브카. 이건 아마도…","JPN":"違うよ、マブカ。これはたぶん……","ENG":"No, Mavka. I think this is...","TWN":"不對，瑪卡，這或許是…"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"아직 확신할 순 없지만… 호, 혹시… 예전부터 아팠었어?","JPN":"まだ確信できないけど……も、もしかして……前から悪かったの？","ENG":"I can't be certain, but... h-has she been sick for long?","TWN":"雖然還不能確定……但，難道……她以前就一直不舒服嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이것저것 약을 먹긴 했었어. 하지만 최근에는 잘 안 먹었었는데….","JPN":"薬をいくつか飲んでたけど、最近はあまり飲んでなかったのに……","ENG":"She took several meds. But she hasn't taken them recently...","TWN":"莎夏吃過很多藥，不過最近沒怎麼吃了……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"마브카 저기…!","JPN":"マブカ、あの……！","ENG":"Mavka, um...!","TWN":"瑪卡，這邊……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"사, 사샤는 우리가 맡아서 치료해 줄게!","JPN":"サ、サシャは私たちが責任持って治療してあげる！","ENG":"W-we'll treat Sasha!","TWN":"莎，莎夏交給我們治療吧！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"안돼. 너희들한테 사샤를 맡길 순 없어.","JPN":"ダメ。あなたたちにサシャを任せるわけにはいかない。","ENG":"No. I can't leave Sasha in your hands.","TWN":"不行，我不能把莎夏交給你們。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"분명 독감일 거야. 최근 추운데도 밖에서 일했으니까.","JPN":"きっとインフルエンザだよ。最近寒いのに外で働いていたから。","ENG":"I'm sure it's just the flu because she's been out in the cold these past few days.","TWN":"肯定只是流感，最近天氣這麼冷還在外面工作。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아는 약국이 있어. 너희들한테만큼은 절대로 맡길 수 없어!","JPN":"知り合いの薬屋がある。あなたたちにだけは絶対任せられない！","ENG":"There's a pharmacy I know. So I'm never leaving her with you!","TWN":"我知道有家藥店，絕對不能交給你們！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"마을의 의사들은 전부 무면허 의사들뿐이던데….","JPN":"村の医者はみんな闇医者だったけど……","ENG":"I heard all the doctors in the village were unlicensed...","TWN":"村裡的醫生全都是無照醫生……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그런 사람들은 절대 사샤를 치료할 수 없을 거야!","JPN":"その人たちは絶対サシャのことを治せないよ！","ENG":"They will never be able to treat Sasha!","TWN":"那種人絕對治不好莎夏！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"우리 의학을 믿어줘! 드레카는 접근하지 못하게 할 테니까…!","JPN":"私たちの医学を信じて！　ドレカは近づけないようにするから……！","ENG":"Trust our medicine! I'll make sure Dreka doesn't get close to her...!","TWN":"相信我們的醫術！我會不讓德蕾卡靠近的……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그… 노력은 해볼게.","JPN":"その……努力はしてみる。","ENG":"A-at least... I'll try to.","TWN":"至，至少……我會盡力……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……대신 내가 사샤 곁에 있겠어.","JPN":"……その代わり、私がサシャのそばにいる。","ENG":"...Then I want to be with Sasha.","TWN":"……我會一直陪在莎夏身邊。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"절대 떨어지지 않을 거니까, 허튼짓 할 생각하지 마.","JPN":"絶対離れないから、余計なことはしないで。","ENG":"I'm never leaving her side, so don't try anything stupid.","TWN":"絕對不會離開，所以別想耍花招。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"으, 응! 믿어줘서 고마워!","JPN":"う、うん！　信じてくれてありがとう！","ENG":"O-okay! Thanks for trusting us!","TWN":"呃，嗯！謝謝你相信我！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};